import type {
  FilterFieldComparisonOperators,
  FilterFieldPrimitive,
} from '../../types/validation.js';

const OperatorsWithNames: Record<
  string,
  FilterFieldComparisonOperators | undefined
> = {
  '=': 'equals',
  '!=': 'not-equals',
  '<': 'less-than',
  '<=': 'less-or-equal',
  '>': 'greater-than',
  '>=': 'greater-or-equal',
  '= *': 'exists', // first match
  '=*': 'exists',
  '!= *': 'not-exists', // first match
  '!=*': 'not-exists',
  '~': 'matches-phrase',
  '!~': 'not-matches-phrase',
  '*~': 'search',
  '* ~': 'search',
  in: 'in',
  'not in': 'not in',
  contains: 'contains',
  'starts-with': 'starts-with',
  'ends-with': 'ends-with',
  'not-contains': 'not-contains',
  'not-starts-with': 'not-starts-with',
  'not-ends-with': 'not-ends-with',
};

/**
 * function to match the operator as used in the filterfield with its full name
 * e.g. '=' returns 'equals'
 * @internal
 */
export const getOperatorName = (operator: string) =>
  OperatorsWithNames[operator] ?? '';

/**
 * function to match the full name of an comparisonOperator with its short name
 * e.g. 'equals' returns '='
 * @internal
 */
export const getOperatorShortName = (
  comparisonOperator: FilterFieldComparisonOperators,
) => {
  for (const [key, value] of Object.entries(OperatorsWithNames)) {
    if (value === comparisonOperator) {
      return key;
    }
  }
  return undefined;
};

const baseOperators: Array<FilterFieldComparisonOperators> = [
  'equals',
  'not-equals',
  'exists',
  'not-exists',
];

const stringOperators: Array<FilterFieldComparisonOperators> = [
  'matches-phrase',
  'not-matches-phrase',
  'contains',
  'starts-with',
  'ends-with',
  'not-contains',
  'not-starts-with',
  'not-ends-with',
];

const listOperators: Array<FilterFieldComparisonOperators> = ['in', 'not in'];
const numericOperators: Array<FilterFieldComparisonOperators> = [
  'less-than',
  'less-or-equal',
  'greater-than',
  'greater-or-equal',
];

/**
 * Returns the valid operators for the given type
 * @internal
 */
export const getAllowedOperatorsForType = (
  type: FilterFieldPrimitive | string,
): Array<FilterFieldComparisonOperators> => {
  switch (type) {
    case 'String':
      return [...baseOperators, ...listOperators, ...stringOperators];
    case 'Number':
      return [...baseOperators, ...numericOperators, ...listOperators];
    case 'Boolean':
      return [...baseOperators];
    case 'Timestamp':
    case 'IPAddress':
    case 'Duration':
      return [...baseOperators, ...numericOperators, ...listOperators];
    case 'UID':
    case 'SmartscapeId':
      return [...baseOperators, ...listOperators];
    case 'JSONPath':
    case 'Any':
    default:
      return [
        ...baseOperators,
        ...numericOperators,
        ...listOperators,
        ...stringOperators,
      ];
  }
};

/**
 * Default allowed operators
 * @public
 */
export const FILTERFIELD_DEFAULT_OPERATORS: FilterFieldComparisonOperators[] = [
  'equals',
  'not-equals',
  'greater-than',
  'greater-or-equal',
  'less-than',
  'less-or-equal',
  'in',
  'not in',
  'starts-with',
  'contains',
  'ends-with',
  'not-starts-with',
  'not-contains',
  'not-ends-with',
  'exists',
  'not-exists',
];
